      strings:\n\
        $a = /foo(bar|baz)/ xor\n\
      condition:\n\
        $a\n\
    }", ERROR_SYNTAX_ERROR);

  assert_error(
    "rule test {\n\
      strings:\n\
        $a = \"ab\" xor xor\n\
      condition:\n\
        $a\n\
    }", ERROR_DUPLICATED_MODIFIER);

  // We should have no matches here because we are not generating the wide
