    }", "tests/data/xorwideandascii.out");

  assert_true_rule_file(
    "rule test {\n\
      strings:\n\
        $a = \"This program cannot\" wide ascii\n\
      condition:\n\
        #a == 2\n\
    }", "tests/data/xorwideandascii.out");

  assert_error(
    "rule test {\n\
      strings:\n\
        $a = \"ab\" xor nocase\n\
      condition:\n\
        true\n\
    }", ERROR_INVALID_MODIFIER);

  assert_true_rule(
